// Use Odock's MCP endpoint directly from the official TypeScript MCP client
import {
  Client,
  StreamableHTTPClientTransport,
} from "@modelcontextprotocol/client"

const client = new Client({
  name: "odock-github-tools-client",
  version: "1.0.0"
})

const transport = new StreamableHTTPClientTransport(
  new URL(process.env.ODOCK_MCP_URL!),
  {
    authProvider: {
      token: async () => process.env.ODOCK_API_KEY!
    }
  }
)

await client.connect(transport)
const result = await client.callTool({ name: "get_me", arguments: {} })
console.log(result)

# Use Odock's MCP endpoint as a LangChain tool source
import asyncio
import os

from langchain.agents import create_agent
from langchain_mcp_adapters.client import MultiServerMCPClient

async def main():
    client = MultiServerMCPClient({
        "github": {
            "transport": "http",
            "url": os.environ["ODOCK_MCP_URL"],
            "headers": {
                "Authorization": f"Bearer {os.environ['ODOCK_API_KEY']}"
            }
        }
    })

    tools = await client.get_tools()
    agent = create_agent("openai:gpt-4.1", tools)
    print(await agent.ainvoke({"messages": [{"role": "user", "content": "Who am I on GitHub?"}]}))

asyncio.run(main())

// Use Odock's MCP endpoint as an AI SDK MCP transport
import { createMCPClient } from "@ai-sdk/mcp"

const mcpClient = await createMCPClient({
  transport: {
    type: "http",
    url: process.env.ODOCK_MCP_URL!,
    headers: {
      Authorization: `Bearer ${process.env.ODOCK_API_KEY!}`
    },
    redirect: "error"
  }
})

const tools = await mcpClient.tools()
console.log(Object.keys(tools))
await mcpClient.close()

