package custom_sso

import "github.com/corneille/odock-server/internal/plugin"

type Plugin struct{}

func (p *Plugin) Name() string { return "custom_sso" }

func (p *Plugin) Phases() []plugin.Phase {
  return []plugin.Phase{plugin.PhasePreRoute}
}

func (p *Plugin) ParallelSafe() bool { return true }

func (p *Plugin) Matches(_ *plugin.Context) bool { return true }

func (p *Plugin) Handle(ctx *plugin.Context, phase plugin.Phase) plugin.PluginResult {
  if ctx == nil || ctx.Req == nil || ctx.Req.Request == nil {
    return plugin.PluginResult{}
  }
  if ctx.Req.Metadata == nil {
    ctx.Req.Metadata = map[string]any{}
  }
  ctx.Req.Metadata["auth_source"] = "sso"
  ctx.Req.Metadata["verified_roles"] = []string{"admin", "analyst"}
  return plugin.PluginResult{}
}

