// internal/plugins/semantic_cache/plugin.go
package semantic_cache

import "github.com/corneille/odock-server/internal/plugin"

type Plugin struct{}

func (p *Plugin) Name() string { return "semantic_cache" }

func (p *Plugin) Phases() []plugin.Phase {
  return []plugin.Phase{plugin.PhasePreUpstream, plugin.PhasePostUpstream}
}

func (p *Plugin) ParallelSafe() bool { return false }

func (p *Plugin) Matches(_ *plugin.Context) bool { return true }

func (p *Plugin) Handle(ctx *plugin.Context, phase plugin.Phase) plugin.PluginResult {
  if ctx == nil {
    return plugin.PluginResult{}
  }
  switch phase {
  case plugin.PhasePreUpstream:
    tagSemanticCacheKey(ctx.Req)
  case plugin.PhasePostUpstream:
    storeSemanticCacheEntry(ctx.Req, ctx.Resp)
  }
  return plugin.PluginResult{}
}

