  -H "Authorization: Bearer $ODOCK_API_KEY" \
  -H "Content-Type: application/json" \
  -d '{
    "jsonrpc": "2.0",
    "id": "tools-list-1",
    "method": "tools/list",
    "params": {}
  }'

import { Client } from "@modelcontextprotocol/sdk/client/index.js";
import { StreamableHTTPClientTransport } from "@modelcontextprotocol/sdk/client/streamableHttp.js";

// Point the MCP SDK at Odock's gateway endpoint
const transport = new StreamableHTTPClientTransport(
  new URL("https://api.odock.ai/v1/mcp/github-tools-http"),
  {
    requestInit: {
      headers: {
        Authorization: `Bearer ${process.env.ODOCK_API_KEY}`,
      },
    },
  }
);

const client = new Client({ name: "odock-app", version: "1.0.0" });
await client.connect(transport);

// Discover tools after Odock auth and governance checks
const tools = await client.listTools();
const result = await client.callTool({
  name: "get_me",
  arguments: {},
});
